urlset:
{{ $now := now }}
{{ range .Site.RegularPages }}
  {{/* 🎯 On retient les pages possédant une référence d'AVP et dont la date de clôture
       n'est pas dépassée. (Le champ `actif` n'existe pas dans le front-matter : il vit
       dans BigQuery ; les AVP clos sont de toute façon supprimés du dépôt par le fetcher.) */}}
  {{ if .Params.ref }}
    {{ $ouvert := true }}
    {{ with .Params.date_cloture }}
      {{ if lt (time.AsTime .) $now }}{{ $ouvert = false }}{{ end }}
    {{ end }}
    {{ if $ouvert }}

    {{ .Permalink }}
    {{ .Lastmod.Format "2006-01-02T15:04:05-07:00" }}
    daily
    0.8

    {{ end }}
  {{ end }}
{{ end }}
